import React, { useState } from 'react';

function PeopleWorked({ data }) {
  const [currentIndex, setCurrentIndex] = useState(0);

  if (!data || data.length === 0) return null;

  const handlePrev = () => {
    setCurrentIndex((prevIndex) => 
      prevIndex === 0 ? data.length - 1 : prevIndex - 1
    );
  };

  const handleNext = () => {
    setCurrentIndex((prevIndex) => 
      prevIndex === data.length - 1 ? 0 : prevIndex + 1
    );
  };

  const currentPerson = data[currentIndex];

  return (
    <section id="people-worked" className="py-8 md:py-12 bg-white">
      <div className="max-w-7xl mx-auto px-4">
        <p className="text-sm uppercase tracking-widest text-orange-500 font-bold mb-8">
          People I Worked With
        </p>

        <div className="grid md:grid-cols-2 gap-8 items-center">
          {/* Testimonial Card */}
          <div className="bg-gray-50 p-8 md:p-12 rounded-lg border border-gray-200 min-h-64 flex flex-col justify-between">
            <p className="text-lg text-gray-700 leading-relaxed mb-8">
              {currentPerson.testimonial}
            </p>
            
            {/* Person Info */}
            <div className="flex items-center gap-4">
              {currentPerson.avatar && (
                <div className="w-16 h-16 rounded-full overflow-hidden flex-shrink-0 bg-gray-300">
                  <img 
                    src={currentPerson.avatar} 
                    alt={currentPerson.name}
                    className="w-full h-full object-cover"
                  />
                </div>
              )}
              <div>
                <h4 className="text-lg font-black text-gray-900">
                  {currentPerson.name}
                </h4>
                <p className="text-sm text-gray-600 uppercase tracking-wide">
                  {currentPerson.role}
                </p>
              </div>
            </div>
          </div>

          {/* Right Side - Other testimonials preview & Navigation */}
          <div className="space-y-6">
            {/* Show next testimonials in line */}
            <div className="space-y-4">
              {[1, 2].map((offset) => {
                const nextIndex = (currentIndex + offset) % data.length;
                const person = data[nextIndex];
                return (
                  <div key={nextIndex} className="flex items-start gap-4 p-4 bg-gray-50 rounded-lg border border-gray-200 opacity-60 hover:opacity-100 transition-opacity cursor-pointer">
                    {person.avatar && (
                      <div className="w-12 h-12 rounded-full overflow-hidden flex-shrink-0 bg-gray-300">
                        <img 
                          src={person.avatar} 
                          alt={person.name}
                          className="w-full h-full object-cover"
                        />
                      </div>
                    )}
                    <div className="min-w-0">
                      <p className="text-sm text-gray-600 line-clamp-2">
                        {person.testimonial}
                      </p>
                      <p className="text-xs font-bold text-gray-900 mt-1">
                        {person.name}
                      </p>
                    </div>
                  </div>
                );
              })}
            </div>

            {/* Navigation Buttons */}
            <div className="flex gap-4 pt-4">
              <button
                onClick={handlePrev}
                className="w-12 h-12 rounded-full bg-gray-200 hover:bg-gray-900 text-gray-900 hover:text-white flex items-center justify-center transition-colors"
                aria-label="Previous testimonial"
              >
                ←
              </button>
              <button
                onClick={handleNext}
                className="w-12 h-12 rounded-full bg-gray-200 hover:bg-gray-900 text-gray-900 hover:text-white flex items-center justify-center transition-colors"
                aria-label="Next testimonial"
              >
                →
              </button>
            </div>

            {/* Indicators */}
            <div className="flex gap-2">
              {data.map((_, index) => (
                <button
                  key={index}
                  onClick={() => setCurrentIndex(index)}
                  className={`w-2 h-2 rounded-full transition-colors ${
                    index === currentIndex ? 'bg-gray-900' : 'bg-gray-300'
                  }`}
                  aria-label={`Go to testimonial ${index + 1}`}
                />
              ))}
            </div>
          </div>
        </div>
      </div>
    </section>
  );
}

export default PeopleWorked;
